  1	import * as React from 'react';
  2	import {
  3	  ListObjectsV2CommandOutput,
  4	  ListBucketsCommandOutput,
  5	  ListObjectVersionsCommandOutput,
  6	} from '@aws-sdk/client-s3';
  7	import { ListCommandOutput } from '@odf/shared/s3';
  8	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  9	import { K8sResourceCommon } from '@openshift-console/dynamic-plugin-sdk';
 10	import * as _ from 'lodash-es';
 11	import { TriggerWithOptionsArgs } from 'swr/dist/mutation';
 12	import { Button, ButtonVariant } from '@patternfly/react-core';
 13	import { AngleLeftIcon, AngleRightIcon } from '@patternfly/react-icons';
 14	
 15	export type VersionToken = { keyMarker: string; versionIdMarker: string };
 16	
 17	export type ContinuationVersionsTokens = {
 18	  previous: VersionToken[];
 19	  current: VersionToken;
 20	  next: VersionToken;
 21	};
 22	
 23	export type ContinuationTokens = {
 24	  previous: string[];
 25	  current: string;
 26	  next: string;
 27	};
 28	
 29	export type PaginationProps = {
 30	  onNext: () => void;
 31	  onPrevious: () => void;
 32	  disableNext: boolean;
 33	  disablePrevious: boolean;
 34	  fromCount: number;
 35	  toCount: number;
 36	};
 37	
 38	type Trigger<T> = TriggerWithOptionsArgs<T, any, string, string | VersionToken>;
 39	
 40	const getNextMarkers = (
 41	  response: ListObjectVersionsCommandOutput
 42	): VersionToken =>
 43	  response?.IsTruncated
 44	    ? {
 45	        keyMarker: response?.NextKeyMarker,
 46	        versionIdMarker: response?.NextVersionIdMarker,
 47	      }
 48	    : null;
 49	
 50	const getNextContinuationToken = (
 51	  response: ListCommandOutput,
 52	  containsNextContinuation = true
 53	): string =>
 54	  containsNextContinuation
 55	    ? (response as ListObjectsV2CommandOutput).NextContinuationToken
 56	    : (response as ListBucketsCommandOutput).ContinuationToken;
 57	
 58	const continuationTokensSetter = <T extends ListCommandOutput>(
 59	  setContinuationTokens: React.Dispatch<
 60	    React.SetStateAction<ContinuationTokens | ContinuationVersionsTokens>
 61	  >,
 62	  response: T,
 63	  isNext: boolean,
 64	  setSelectedRows?: React.Dispatch<React.SetStateAction<K8sResourceCommon[]>>,
 65	  containsNextContinuation?: boolean,
 66	  containsMarkers?: boolean
 67	) => {
 68	  setContinuationTokens((oldTokens) => {
 69	    const newTokens = _.cloneDeep(oldTokens);
 70	    if (isNext) {
 71	      newTokens.previous.push(newTokens.current as any);
 72	      newTokens.current = newTokens.next;
 73	    } else {
 74	      newTokens.current = newTokens.previous.pop();
 75	    }
 76	
 77	    newTokens.next = containsMarkers
 78	      ? getNextMarkers(response)
 79	      : getNextContinuationToken(response, containsNextContinuation);
 80	
 81	    return newTokens;
 82	  });
 83	  !!setSelectedRows && setSelectedRows([]);
 84	};
 85	
 86	export const fetchS3Resources = async <T extends ListCommandOutput>(
 87	  setContinuationTokens: React.Dispatch<
 88	    React.SetStateAction<ContinuationTokens | ContinuationVersionsTokens>
 89	  >,
 90	  trigger: Trigger<T>,
 91	  isNext: boolean,
 92	  paginationToken: string | VersionToken,
 93	  setSelectedRows?: React.Dispatch<React.SetStateAction<K8sResourceCommon[]>>,
 94	  containsNextContinuation?: boolean,
 95	  containsMarkers = false
 96	) => {
 97	  try {
 98	    const response: T = await trigger(paginationToken);
 99	    continuationTokensSetter<T>(
100	      setContinuationTokens,
101	      response,
102	      isNext,
103	      setSelectedRows,
104	      containsNextContinuation,
105	      containsMarkers
106	    );
107	  } catch (err) {
108	    // no need to handle any error here, use "error" object directly from the "useSWRMutation" hook
109	    // eslint-disable-next-line no-console
110	    console.error(err);
111	  }
112	};
113	
114	// for refreshing (re-feching) s3 resources from start, once state has changed by adding/deleted
115	export const continuationTokensRefresher = async <T extends ListCommandOutput>(
116	  setContinuationTokens: React.Dispatch<
117	    React.SetStateAction<ContinuationTokens | ContinuationVersionsTokens>
118	  >,
119	  trigger: Trigger<T>,
120	  setSelectedRows?: React.Dispatch<React.SetStateAction<K8sResourceCommon[]>>,
121	  containsNextContinuation?: boolean,
122	  containsMarkers = false
123	) => {
124	  try {
125	    const response: T = await trigger();
126	    containsMarkers
127	      ? setContinuationTokens({
128	          previous: [null],
129	          current: null,
130	          next: getNextMarkers(response),
131	        } as ContinuationVersionsTokens)
132	      : setContinuationTokens({
133	          previous: [''],
134	          current: '',
135	          next: getNextContinuationToken(response, containsNextContinuation),
136	        } as ContinuationTokens);
137	    !!setSelectedRows && setSelectedRows([]);
138	  } catch (err) {
139	    // no need to handle any error here, use "error" object directly from the "useSWRMutation" hook
140	    // eslint-disable-next-line no-console
141	    console.error(err);
142	  }
143	};
144	
145	const getFromCount = (
146	  continuationTokens: ContinuationTokens | ContinuationVersionsTokens,
147	  currentPageCount: number,
148	  maxResponses: number
149	): number => {
150	  if (currentPageCount === 0) return 0;
151	  const prevLen = continuationTokens.previous?.length || 0;
152	  return prevLen === 0 ? prevLen : (prevLen - 1) * maxResponses + 1;
153	};
154	
155	const getToCount = (fromCount: number, currentPageCount: number): number => {
156	  const count = fromCount - 1 + currentPageCount;
157	  return count <= 0 ? 0 : count;
158	};
159	
160	export const getPaginationCount = (
161	  continuationTokens: ContinuationTokens | ContinuationVersionsTokens,
162	  currentPageCount: number,
163	  maxResponses: number
164	) => {
165	  const fromCount = getFromCount(
166	    continuationTokens,
167	    currentPageCount,
168	    maxResponses
169	  );
170	  const toCount = getToCount(fromCount, currentPageCount);
171	  return [toCount, fromCount];
172	};
173	
174	export const Pagination: React.FC<PaginationProps> = ({
175	  onNext,
176	  onPrevious,
177	  disableNext,
178	  disablePrevious,
179	  fromCount,
180	  toCount,
181	}) => {
182	  const { t } = useCustomTranslation();
183	
184	  const totalCount = disableNext ? toCount : t('many');
185	  return (
186	    <div className="pf-v6-u-display-flex pf-v6-u-flex-direction-row">
187	      <b className="pf-v6-u-mt-xs">
188	        {t('{{ fromCount }} - {{ toCount }} of {{ totalCount }}', {
189	          fromCount,
190	          toCount,
191	          totalCount,
192	        })}
193	      </b>
194	      <Button
195	        variant={ButtonVariant.plain}
196	        className="pf-v6-u-mr-xs"
197	        isDisabled={disablePrevious}
198	        onClick={onPrevious}
199	      >
200	        <AngleLeftIcon />
201	      </Button>
202	      <Button
203	        variant={ButtonVariant.plain}
204	        className="pf-v6-u-ml-xs"
205	        isDisabled={disableNext}
206	        onClick={onNext}
207	      >
208	        <AngleRightIcon />
209	      </Button>
210	    </div>
211	  );
212	};

